import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function BillsHistory() {
  const navigate = useNavigate();
  const employee = JSON.parse(localStorage.getItem("employee")); // login user
  const empId = employee?.empld;

  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");
  const [bills, setBills] = useState([]);

  const API = process.env.REACT_APP_API_BASE;

  // LOAD DATA
  const fetchBills = async () => {
    try {
      const res = await axios.get(`${API}/bills-history`, {
        params: { empId, fromDate, toDate }
      });

      setBills(res.data.bills || []);
    } catch (err) {
      console.error("Error fetching bills:", err);
    }
  };

  useEffect(() => {
    fetchBills();
  }, []);

  const applyFilters = () => fetchBills();

  const resetFilters = () => {
    setFromDate("");
    setToDate("");
    fetchBills();
  };

  const downloadReport = () => {
    window.open(`${API}/bills-report?empId=${empId}`, "_blank");
  };

  return (
    <div
      style={{
        backgroundColor: "#E9F7EF",
        minHeight: "100vh",
        padding: "20px",
        display: "flex",
        justifyContent: "center"
      }}
    >
      <div
        style={{
          width: "90%",
          maxWidth: "900px",
          background: "white",
          borderRadius: "16px",
          padding: "20px",
          boxShadow: "0 4px 12px rgba(0,0,0,0.08)"
        }}
      >
        {/* HEADER */}
        <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
          <button
            onClick={() => navigate(-1)}
            style={{
              border: "none",
              background: "none",
              fontSize: "28px",
              cursor: "pointer"
            }}
          >
            ←
          </button>
          <h2 style={{ margin: 0, fontWeight: "600", color: "#1B8B4C" }}>
            Bills History
          </h2>
        </div>

        {/* EMPLOYEE INFO */}
        <p style={{ marginTop: "5px", fontSize: "15px", color: "#444" }}>
          Employee: <b>{employee?.name}</b> • {empId}
        </p>

        {/* FILTER CARD */}
        <div
          style={{
            background: "#F1FAF4",
            padding: "18px",
            borderRadius: "12px",
            marginTop: "15px"
          }}
        >
          <div
            style={{
              display: "flex",
              gap: "10px",
              flexWrap: "wrap"
            }}
          >
            <div style={{ flex: 1 }}>
              <label>From Date</label>
              <input
                type="date"
                value={fromDate}
                onChange={(e) => setFromDate(e.target.value)}
                style={{
                  width: "100%",
                  padding: "10px",
                  borderRadius: "8px",
                  border: "1px solid #ccc"
                }}
              />
            </div>

            <div style={{ flex: 1 }}>
              <label>To Date</label>
              <input
                type="date"
                value={toDate}
                onChange={(e) => setToDate(e.target.value)}
                style={{
                  width: "100%",
                  padding: "10px",
                  borderRadius: "8px",
                  border: "1px solid #ccc"
                }}
              />
            </div>

            <button
              onClick={resetFilters}
              style={{
                padding: "10px 18px",
                background: "#1B8B4C",
                color: "white",
                border: "none",
                borderRadius: "8px",
                height: "40px",
                marginTop: "22px",
                cursor: "pointer"
              }}
            >
              Reset
            </button>
          </div>

          {/* Apply Filter Button */}
          <button
            onClick={applyFilters}
            style={{
              width: "100%",
              background: "#1B8B4C",
              color: "white",
              border: "none",
              borderRadius: "10px",
              padding: "12px",
              marginTop: "12px",
              fontSize: "16px",
              cursor: "pointer"
            }}
          >
            Apply Filters
          </button>
        </div>

        {/* TABLE BOX */}
        <div
          style={{
            background: "white",
            borderRadius: "12px",
            marginTop: "15px",
            padding: "15px",
            border: "1px solid #E0E0E0"
          }}
        >
          <table style={{ width: "100%", textAlign: "left" }}>
            <thead>
              <tr style={{ background: "#F1FAF4" }}>
                <th style={{ padding: "10px" }}>Date</th>
                <th style={{ padding: "10px" }}>File Name</th>
                <th style={{ padding: "10px" }}>Preview</th>
              </tr>
            </thead>

            <tbody>
              {bills.length === 0 ? (
                <tr>
                  <td colSpan="3" style={{ textAlign: "center", padding: "20px" }}>
                    No bills found
                  </td>
                </tr>
              ) : (
                bills.map((b, i) => (
                  <tr key={i}>
                    <td style={{ padding: "10px" }}>{b.date}</td>
                    <td style={{ padding: "10px" }}>{b.fileName}</td>
                    <td style={{ padding: "10px" }}>
                      <a
                        href={b.fileUrl}
                        target="_blank"
                        rel="noreferrer"
                        style={{ color: "#1B8B4C", fontWeight: "600" }}
                      >
                        View
                      </a>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* DOWNLOAD REPORT BUTTON */}
        <div style={{ marginTop: "20px" }}>
          <button
            onClick={downloadReport}
            style={{
              background: "#1B8B4C",
              color: "white",
              padding: "12px 20px",
              border: "none",
              borderRadius: "10px",
              cursor: "pointer"
            }}
          >
            📄 Download Bills Report
          </button>
        </div>
      </div>
    </div>
  );
}
